double calculate_variance_from_sums(double sum_sq_group_totals, double total_weight_double, int D_val) {
    if (D_val <= 0) return 1e18;
    double mean_weight = total_weight_double / D_val;
    double variance = sum_sq_group_totals / D_val - mean_weight * mean_weight;
    return std::max(0.0, variance);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    program_start_time = std::chrono::steady_clock::now();
    uint64_t random_seed = std::chrono::duration_cast<std::chrono::nanoseconds>(std::chrono::steady_clock::now().time_since_epoch()).count();
    rng_engine.seed(random_seed);

    std::cin >> N_items_global >> D_groups_global >> Q_total_global;

    // Reserve queries for group-comparison refinement phase
    // We need at least a few rounds of D comparisons for meaningful refinement
    int refinement_budget = std::min(Q_total_global / 3, D_groups_global * 10);
    // But ensure we have enough for estimation
    int estimation_budget = Q_total_global - refinement_budget;

    std::vector<long long> estimated_weights(N_items_global);

    // Determine how many pivots we can sort within estimation budget
    int k_pivots_chosen = 0;
    if (N_items_global > 0) {
        for (int cur_k_val = N_items_global; cur_k_val >= 1; --cur_k_val) {
            if (calculate_estimated_query_cost(N_items_global, cur_k_val) <= estimation_budget) {
                k_pivots_chosen = cur_k_val;
                break;
            }
        }
    }
    k_pivots_chosen = std::min(k_pivots_chosen, N_items_global);
    if (N_items_global == 0) k_pivots_chosen = 0;

    std::vector<int> pivot_item_indices(k_pivots_chosen);
    if (k_pivots_chosen > 0) {
        std::vector<int> all_item_indices_temp(N_items_global);
        std::iota(all_item_indices_temp.begin(), all_item_indices_temp.end(), 0);
        std::shuffle(all_item_indices_temp.begin(), all_item_indices_temp.end(), rng_engine);
        for (int i = 0; i < k_pivots_chosen; ++i) pivot_item_indices[i] = all_item_indices_temp[i];
    }

    std::vector<int> sorted_pivot_item_indices = pivot_item_indices;

    const int FACTOR_GT_NUM = 200;
    const int FACTOR_LT_NUM = 50;
    const int FACTOR_XJ_FALLBACK_NUM = 100;

    if (k_pivots_chosen == 0) {
        for (int i = 0; i < N_items_global; ++i) estimated_weights[i] = BASE_WEIGHT;
    } else if (k_pivots_chosen == 1) {
        estimated_weights[pivot_item_indices[0]] = BASE_WEIGHT;
        for (int i = 0; i < N_items_global; ++i) {
            if (i == pivot_item_indices[0]) continue;
            char res = compare_single_items(i, pivot_item_indices[0]);
            if (res == '=') estimated_weights[i] = BASE_WEIGHT;
            else if (res == '<') estimated_weights[i] = std::max(1LL, BASE_WEIGHT * FACTOR_LT_NUM / 100);
            else estimated_weights[i] = std::max(1LL, BASE_WEIGHT * FACTOR_GT_NUM / 100);
        }
    } else {
        merge_sort_items(sorted_pivot_item_indices, 0, k_pivots_chosen - 1);

        int p0_idx = sorted_pivot_item_indices[0];
        estimated_weights[p0_idx] = BASE_WEIGHT;

        int p1_idx = sorted_pivot_item_indices[1];
        char res_p1_vs_p0 = compare_single_items(p1_idx, p0_idx);
        if (res_p1_vs_p0 == '=') {
            estimated_weights[p1_idx] = estimated_weights[p0_idx];
        } else if (res_p1_vs_p0 == '<') {
            estimated_weights[p1_idx] = std::max(1LL, estimated_weights[p0_idx] * FACTOR_LT_NUM / 100);
        } else {
            estimated_weights[p1_idx] = std::max(1LL, estimated_weights[p0_idx] * FACTOR_GT_NUM / 100);
        }
        if (estimated_weights[p1_idx] < estimated_weights[p0_idx]) {
            estimated_weights[p1_idx] = estimated_weights[p0_idx];
        }
        if (res_p1_vs_p0 == '>' && estimated_weights[p1_idx] == estimated_weights[p0_idx]) {
            estimated_weights[p1_idx] = estimated_weights[p0_idx] + 1;
        }

        const long long MAX_XJ_INITIAL_HIGH_BOUND = BASE_WEIGHT * (1LL * N_items_global / std::max(1, D_groups_global) + 10);

        for (int j = 2; j < k_pivots_chosen; ++j) {
            int current_pivot_idx = sorted_pivot_item_indices[j];
            int prev_pivot_idx = sorted_pivot_item_indices[j - 1];

            char res_curr_vs_prev = compare_single_items(current_pivot_idx, prev_pivot_idx);
            if (res_curr_vs_prev == '=') {
                estimated_weights[current_pivot_idx] = estimated_weights[prev_pivot_idx];
            } else if (res_curr_vs_prev == '<') {
                estimated_weights[current_pivot_idx] = std::max(1LL, estimated_weights[prev_pivot_idx] * FACTOR_LT_NUM / 100);
            } else {
                long long X_low_bound_val = 1;
                long long X_high_bound_val = MAX_XJ_INITIAL_HIGH_BOUND;
                bool x_low_modified = false;
                bool x_high_modified = false;

                int s_search_low_arr_idx = 0, s_search_high_arr_idx = j - 2;
                int num_s_candidates = (s_search_high_arr_idx - s_search_low_arr_idx + 1);
                int queries_for_this_Xj = 0;
                if (num_s_candidates > 0) {
                    queries_for_this_Xj = static_cast<int>(std::ceil(estimate_log2(static_cast<double>(num_s_candidates))));
                    if (num_s_candidates == 1) queries_for_this_Xj = 1;
                }

                for (int bs_iter = 0; bs_iter < queries_for_this_Xj && queries_made < Q_total_global; ++bs_iter) {
                    if (s_search_low_arr_idx > s_search_high_arr_idx) break;
                    int s_mid_arr_idx = s_search_low_arr_idx + (s_search_high_arr_idx - s_search_low_arr_idx) / 2;
                    int item_s_aux_idx = sorted_pivot_item_indices[s_mid_arr_idx];

                    char res_1v2 = compare_1v2_items_specific(current_pivot_idx, prev_pivot_idx, item_s_aux_idx);
                    if (res_1v2 == '=') {
                        X_low_bound_val = X_high_bound_val = estimated_weights[item_s_aux_idx];
                        x_low_modified = x_high_modified = true;
                        break;
                    } else if (res_1v2 == '<') {
                        X_high_bound_val = estimated_weights[item_s_aux_idx];
                        x_high_modified = true;
                        s_search_high_arr_idx = s_mid_arr_idx - 1;
                    } else {
                        X_low_bound_val = estimated_weights[item_s_aux_idx];
                        x_low_modified = true;
                        s_search_low_arr_idx = s_mid_arr_idx + 1;
                    }
                }

                long long estimated_X_j;
                if (x_low_modified && !x_high_modified) {
                    estimated_X_j = X_low_bound_val * FACTOR_GT_NUM / 100;
                } else if (!x_low_modified && x_high_modified) {
                    estimated_X_j = X_high_bound_val * FACTOR_LT_NUM / 100;
                } else if (x_low_modified && x_high_modified) {
                    estimated_X_j = (X_low_bound_val + X_high_bound_val) / 2;
                } else {
                    estimated_X_j = estimated_weights[prev_pivot_idx] * FACTOR_XJ_FALLBACK_NUM / 100;
                    if (estimated_weights[prev_pivot_idx] > 0 && estimated_X_j == 0) estimated_X_j = 1;
                    else if (estimated_weights[prev_pivot_idx] == 0) {
                        estimated_X_j = std::max(1LL, BASE_WEIGHT * FACTOR_XJ_FALLBACK_NUM / 100);
                    }
                }
                estimated_X_j = std::max(1LL, estimated_X_j);
                estimated_weights[current_pivot_idx] = estimated_weights[prev_pivot_idx] + estimated_X_j;
            }
            if (estimated_weights[current_pivot_idx] < estimated_weights[prev_pivot_idx]) {
                estimated_weights[current_pivot_idx] = estimated_weights[prev_pivot_idx];
            }
            if (res_curr_vs_prev == '>' && estimated_weights[current_pivot_idx] == estimated_weights[prev_pivot_idx]) {
                estimated_weights[current_pivot_idx] = estimated_weights[prev_pivot_idx] + 1;
            }
        }

        // Estimate weights for non-pivot items
        for (int i = 0; i < N_items_global; ++i) {
            bool is_pivot_flag = false;
            for (int p_idx_val = 0; p_idx_val < k_pivots_chosen; ++p_idx_val) {
                if (sorted_pivot_item_indices[p_idx_val] == i) { is_pivot_flag = true; break; }
            }
            if (is_pivot_flag) continue;

            int bs_low_arr_idx = 0, bs_high_arr_idx = k_pivots_chosen - 1;
            int found_pivot_idx_for_eq = -1;

            while (bs_low_arr_idx <= bs_high_arr_idx) {
                if (queries_made >= Q_total_global && found_pivot_idx_for_eq == -1) break;
                int mid_p_arr_idx = bs_low_arr_idx + (bs_high_arr_idx - bs_low_arr_idx) / 2;
                char res_item_vs_p = compare_single_items(i, sorted_pivot_item_indices[mid_p_arr_idx]);
                if (res_item_vs_p == '=') { found_pivot_idx_for_eq = mid_p_arr_idx; break; }
                else if (res_item_vs_p == '<') { bs_high_arr_idx = mid_p_arr_idx - 1; }
                else { bs_low_arr_idx = mid_p_arr_idx + 1; }
            }

            if (found_pivot_idx_for_eq != -1) {
                estimated_weights[i] = estimated_weights[sorted_pivot_item_indices[found_pivot_idx_for_eq]];
                continue;
            }

            int insert_pos_arr_idx = bs_low_arr_idx;
            if (insert_pos_arr_idx == 0) {
                long long w_p0 = estimated_weights[sorted_pivot_item_indices[0]];
                if (k_pivots_chosen >= 2) {
                    long long w_p1 = estimated_weights[sorted_pivot_item_indices[1]];
                    if (w_p1 > w_p0 && w_p0 > 0 && w_p1 != 0) {
                        estimated_weights[i] = std::max(1LL, w_p0 * w_p0 / w_p1);
                    } else {
                        estimated_weights[i] = std::max(1LL, w_p0 * FACTOR_LT_NUM / 100);
                    }
                } else {
                    estimated_weights[i] = std::max(1LL, w_p0 * FACTOR_LT_NUM / 100);
                }
            } else if (insert_pos_arr_idx == k_pivots_chosen) {
                long long w_pk_1 = estimated_weights[sorted_pivot_item_indices[k_pivots_chosen - 1]];
                if (k_pivots_chosen >= 2) {
                    long long w_pk_2 = estimated_weights[sorted_pivot_item_indices[k_pivots_chosen - 2]];
                    if (w_pk_1 > w_pk_2 && w_pk_2 > 0) {
                        estimated_weights[i] = std::max(1LL, w_pk_1 * w_pk_1 / w_pk_2);
                    } else {
                        estimated_weights[i] = std::max(1LL, w_pk_1 * FACTOR_GT_NUM / 100);
                    }
                } else {
                    estimated_weights[i] = std::max(1LL, w_pk_1 * FACTOR_GT_NUM / 100);
                }
            } else {
                long long w_prev_p = estimated_weights[sorted_pivot_item_indices[insert_pos_arr_idx - 1]];
                long long w_next_p = estimated_weights[sorted_pivot_item_indices[insert_pos_arr_idx]];
                if (w_prev_p > 0 && w_next_p > 0) {
                    estimated_weights[i] = static_cast<long long>(std::sqrt(static_cast<double>(w_prev_p) * w_next_p));
                } else {
                    estimated_weights[i] = (w_prev_p + w_next_p) / 2;
                }
                estimated_weights[i] = std::max(w_prev_p, estimated_weights[i]);
                estimated_weights[i] = std::min(w_next_p, estimated_weights[i]);
            }
            if (estimated_weights[i] <= 0) estimated_weights[i] = 1;
        }
    }

    for (int i = 0; i < N_items_global; ++i) {
        if (estimated_weights[i] <= 0) estimated_weights[i] = BASE_WEIGHT;
    }

    // --- Partitioning Phase: LPT greedy + SA ---
    std::vector<int> assignment_array(N_items_global);
    std::vector<long long> group_sums_array(D_groups_global, 0);
    long long total_sum_est_val = 0;
    std::vector<std::vector<int>> group_items_indices(D_groups_global);
    std::vector<int> item_pos_in_group_vector(N_items_global);

    std::vector<std::pair<long long, int>> items_sorted_for_greedy(N_items_global);
    for (int i = 0; i < N_items_global; ++i) {
        items_sorted_for_greedy[i] = {-estimated_weights[i], i};
        total_sum_est_val += estimated_weights[i];
    }
    std::sort(items_sorted_for_greedy.begin(), items_sorted_for_greedy.end());

    for (int i = 0; i < N_items_global; ++i) {
        int item_idx = items_sorted_for_greedy[i].second;
        long long item_w = estimated_weights[item_idx];
        int best_grp = 0;
        long long min_sum = group_sums_array[0];
        for (int j = 1; j < D_groups_global; ++j) {
            if (group_sums_array[j] < min_sum) {
                min_sum = group_sums_array[j];
                best_grp = j;
            }
        }
        assignment_array[item_idx] = best_grp;
        group_sums_array[best_grp] += item_w;
        group_items_indices[best_grp].push_back(item_idx);
        item_pos_in_group_vector[item_idx] = group_items_indices[best_grp].size() - 1;
    }

    double current_sum_sq_group_totals = 0;
    for (long long s : group_sums_array) {
        current_sum_sq_group_totals += static_cast<double>(s) * s;
    }
    double current_var = calculate_variance_from_sums(current_sum_sq_group_totals, static_cast<double>(total_sum_est_val), D_groups_global);

    // SA on estimated weights
    double T = std::max(1.0, current_var * 0.25);
    if (current_var < 1e-9 && total_sum_est_val > 0) {
        T = std::max(1.0, static_cast<double>(total_sum_est_val) / std::max(1, N_items_global) * 0.1);
    }
    if (D_groups_global <= 1) T = 0;

    std::uniform_real_distribution<double> unif_dist(0.0, 1.0);
    int sa_iters_count = 0;
    int no_improvement_streak = 0;
    const int REHEAT_THRESH = N_items_global * 15;
    const int CHECK_TIME_INTERVAL = 256;

    // Run SA for a limited time (leave time for refinement phase)
    std::chrono::milliseconds sa_time_limit_ms(1200); // Use 1.2s for SA, save rest for refinement

    while (D_groups_global > 1 && N_items_global > 0) {
        sa_iters_count++;
        if (sa_iters_count % CHECK_TIME_INTERVAL == 0) {
            auto time_now = std::chrono::steady_clock::now();
            if (std::chrono::duration_cast<std::chrono::milliseconds>(time_now - program_start_time) >= sa_time_limit_ms) break;
            T *= 0.9999;
            if (no_improvement_streak > REHEAT_THRESH && T < current_var * 0.05 && current_var > 1.0) {
                T = std::max(1.0, current_var * 0.125);
                no_improvement_streak = 0;
            }
        }
        if (T < 1e-12 && current_var > 1e-9) T = 1e-9;
        if (T < 1e-12 && current_var < 1.0 + 1e-9) break;

        bool try_swap = (rng_engine() % 3 == 0);

        if (!try_swap) {
            int item_to_move = rng_engine() % N_items_global;
            int old_grp = assignment_array[item_to_move];
            int new_grp = rng_engine() % D_groups_global;
            while (new_grp == old_grp) new_grp = rng_engine() % D_groups_global;

            long long item_w = estimated_weights[item_to_move];
            long long old_sum_A = group_sums_array[old_grp];
            long long old_sum_B = group_sums_array[new_grp];
            long long new_sum_A = old_sum_A - item_w;
            long long new_sum_B = old_sum_B + item_w;

            double new_sum_sq = current_sum_sq_group_totals;
            new_sum_sq -= static_cast<double>(old_sum_A) * old_sum_A + static_cast<double>(old_sum_B) * old_sum_B;
            new_sum_sq += static_cast<double>(new_sum_A) * new_sum_A + static_cast<double>(new_sum_B) * new_sum_B;
            double new_var = calculate_variance_from_sums(new_sum_sq, static_cast<double>(total_sum_est_val), D_groups_global);
            double delta_V = new_var - current_var;

            if (delta_V < 0 || (T > 1e-12 && unif_dist(rng_engine) < std::exp(-delta_V / T))) {
                current_var = new_var;
                current_sum_sq_group_totals = new_sum_sq;
                group_sums_array[old_grp] = new_sum_A;
                group_sums_array[new_grp] = new_sum_B;
                assignment_array[item_to_move] = new_grp;

                int pos = item_pos_in_group_vector[item_to_move];
                if (!group_items_indices[old_grp].empty()) {
                    int last_item = group_items_indices[old_grp].back();
                    if (item_to_move != last_item) {
                        group_items_indices[old_grp][pos] = last_item;
                        item_pos_in_group_vector[last_item] = pos;
                    }
                    group_items_indices[old_grp].pop_back();
                }
                group_items_indices[new_grp].push_back(item_to_move);
                item_pos_in_group_vector[item_to_move] = group_items_indices[new_grp].size() - 1;

                if (delta_V < -1e-9) no_improvement_streak = 0; else no_improvement_streak++;
            } else {
                no_improvement_streak++;
            }
        } else {
            int grp1 = rng_engine() % D_groups_global;
            int grp2 = rng_engine() % D_groups_global;
            while (grp2 == grp1) grp2 = rng_engine() % D_groups_global;

            if (group_items_indices[grp1].empty() || group_items_indices[grp2].empty()) {
                no_improvement_streak++;
                continue;
            }

            int item1 = group_items_indices[grp1][rng_engine() % group_items_indices[grp1].size()];
            int item2 = group_items_indices[grp2][rng_engine() % group_items_indices[grp2].size()];

            long long w1 = estimated_weights[item1];
            long long w2 = estimated_weights[item2];

            long long old_sum_g1 = group_sums_array[grp1];
            long long old_sum_g2 = group_sums_array[grp2];
            long long new_sum_g1 = old_sum_g1 - w1 + w2;
            long long new_sum_g2 = old_sum_g2 - w2 + w1;

            double new_sum_sq = current_sum_sq_group_totals;
            new_sum_sq -= static_cast<double>(old_sum_g1) * old_sum_g1 + static_cast<double>(old_sum_g2) * old_sum_g2;
            new_sum_sq += static_cast<double>(new_sum_g1) * new_sum_g1 + static_cast<double>(new_sum_g2) * new_sum_g2;
            double new_var = calculate_variance_from_sums(new_sum_sq, static_cast<double>(total_sum_est_val), D_groups_global);
            double delta_V = new_var - current_var;

            if (delta_V < 0 || (T > 1e-12 && unif_dist(rng_engine) < std::exp(-delta_V / T))) {
                current_var = new_var;
                current_sum_sq_group_totals = new_sum_sq;
                group_sums_array[grp1] = new_sum_g1;
                group_sums_array[grp2] = new_sum_g2;
                assignment_array[item1] = grp2;
                assignment_array[item2] = grp1;

                int pos1 = item_pos_in_group_vector[item1];
                int back1 = group_items_indices[grp1].back();
                if (item1 != back1) {
                    group_items_indices[grp1][pos1] = back1;
                    item_pos_in_group_vector[back1] = pos1;
                }
                group_items_indices[grp1].pop_back();

                int pos2 = item_pos_in_group_vector[item2];
                int back2 = group_items_indices[grp2].back();
                if (item2 != back2) {
                    group_items_indices[grp2][pos2] = back2;
                    item_pos_in_group_vector[back2] = pos2;
                }
                group_items_indices[grp2].pop_back();

                group_items_indices[grp2].push_back(item1);
                item_pos_in_group_vector[item1] = group_items_indices[grp2].size() - 1;
                group_items_indices[grp1].push_back(item2);
                item_pos_in_group_vector[item2] = group_items_indices[grp1].size() - 1;

                if (delta_V < -1e-9) no_improvement_streak = 0; else no_improvement_streak++;
            } else {
                no_improvement_streak++;
            }
        }
    }

    // --- Group-comparison refinement phase ---
    // Use remaining queries to compare actual group sums and rebalance
    int remaining_queries = Q_total_global - queries_made;

    if (remaining_queries > 0 && D_groups_global > 1) {
        // Iteratively: find heaviest & lightest groups via pairwise comparison,
        // then try swapping items between them

        while (queries_made < Q_total_global) {
            auto time_now = std::chrono::steady_clock::now();
            if (std::chrono::duration_cast<std::chrono::milliseconds>(time_now - program_start_time) >= time_limit_ms) break;

            int queries_left = Q_total_global - queries_made;
            // Need at least D-1 queries to find heaviest group via tournament
            // Plus D-1 to find lightest = 2*(D-1) per round at minimum
            // Plus some for binary search within groups
            if (queries_left < 2 * (D_groups_global - 1) + 1) {
                // Not enough for a full round; just waste remaining
                break;
            }

            // Find heaviest group via tournament
            int heaviest_grp = 0;
            for (int g = 1; g < D_groups_global && queries_made < Q_total_global; g++) {
                if (group_items_indices[heaviest_grp].empty()) { heaviest_grp = g; continue; }
                if (group_items_indices[g].empty()) continue;
                char res = compare_groups(group_items_indices[heaviest_grp], group_items_indices[g]);
                if (res == '<') heaviest_grp = g;
            }

            // Find lightest group via tournament
            int lightest_grp = (heaviest_grp == 0) ? 1 : 0;
            for (int g = 0; g < D_groups_global && queries_made < Q_total_global; g++) {
                if (g == heaviest_grp) continue;
                if (group_items_indices[lightest_grp].empty()) { lightest_grp = g; continue; }
                if (group_items_indices[g].empty()) continue;
                if (g == lightest_grp) continue;
                char res = compare_groups(group_items_indices[lightest_grp], group_items_indices[g]);
                if (res == '>') lightest_grp = g;
            }

            if (heaviest_grp == lightest_grp) break;
            if (group_items_indices[heaviest_grp].empty()) break;

            // Compare heaviest vs lightest to confirm they're actually different
            if (queries_made < Q_total_global) {
                char confirm = compare_groups(group_items_indices[heaviest_grp], group_items_indices[lightest_grp]);
                if (confirm != '>') break; // Already balanced enough
            }

            // Try to move an item from heaviest to lightest
            // Use binary search to find the item in heaviest group that, when moved,
            // best balances the two groups
            // Strategy: find the smallest item in heaviest group and move it to lightest
            // (since we want to reduce heaviest and increase lightest minimally)

            // Actually, the ideal item to move has weight ≈ (sum_heavy - sum_light) / 2
            // Let's find an item close to that using our estimated weights
            long long target_move_weight = (group_sums_array[heaviest_grp] - group_sums_array[lightest_grp]) / 2;

            // Find item in heaviest group closest to target_move_weight
            int best_item_to_move = -1;
            long long best_diff = LLONG_MAX;
            for (int item : group_items_indices[heaviest_grp]) {
                long long diff = std::abs(estimated_weights[item] - target_move_weight);
                if (diff < best_diff) {
                    best_diff = diff;
                    best_item_to_move = item;
                }
            }

            if (best_item_to_move == -1) break;

            // Alternatively, try a swap: move best_item from heaviest to lightest,
            // and find an item in lightest to move to heaviest
            // The ideal swap: move item with weight W_h from heavy, move item with weight W_l from light
            // Net change: heavy loses (W_h - W_l), light gains (W_h - W_l)
            // Ideal: W_h - W_l = (sum_heavy - sum_light) / 2

            // Simple approach: just move the item
            int item_to_move = best_item_to_move;
            long long item_w = estimated_weights[item_to_move];

            // Update assignment
            int old_grp = heaviest_grp;
            int new_grp = lightest_grp;

            // Update sums
            group_sums_array[old_grp] -= item_w;
            group_sums_array[new_grp] += item_w;
            assignment_array[item_to_move] = new_grp;

            // Update group membership
            int pos = item_pos_in_group_vector[item_to_move];
            if (!group_items_indices[old_grp].empty()) {
                int last_item = group_items_indices[old_grp].back();
                if (item_to_move != last_item) {
                    group_items_indices[old_grp][pos] = last_item;
                    item_pos_in_group_vector[last_item] = pos;
                }
                group_items_indices[old_grp].pop_back();
            }
            group_items_indices[new_grp].push_back(item_to_move);
            item_pos_in_group_vector[item_to_move] = group_items_indices[new_grp].size() - 1;

            // Recalculate variance tracking
            current_sum_sq_group_totals = 0;
            for (long long s : group_sums_array) {
                current_sum_sq_group_totals += static_cast<double>(s) * s;
            }
            total_sum_est_val = 0;
            for (long long s : group_sums_array) total_sum_est_val += s;
        }
    }

    // Exhaust any remaining queries
    while (queries_made < Q_total_global) {
        perform_query_actual({0}, {1});
    }

    for (int i = 0; i < N_items_global; ++i) {
        std::cout << assignment_array[i] << (i == N_items_global - 1 ? "" : " ");
    }
