        for (int ih : group_items_indices[heaviest_grp]) {
            for (int il : group_items_indices[lightest_grp]) {
                long long swap_diff = estimated_weights[ih] - estimated_weights[il];
                if (swap_diff <= 0) continue; // only consider swaps that transfer weight from heavy to light
                long long err = std::abs(swap_diff - target_diff);
                if (err < best_swap_err) {
                    best_swap_err = err;
                    best_h = ih;
                    best_l = il;
                }
            }
