        // Use binary search to find the item in heaviest group that, when moved,
        // best balances the two groups
        // Strategy: find the smallest item in heaviest group and move it to lightest
        // (since we want to reduce heaviest and increase lightest minimally)

        // Actually, the ideal item to move has weight ≈ (sum_heavy - sum_light) / 2
        // Let's find an item close to that using our estimated weights
        long long target_move_weight = (group_sums_array[heaviest_grp] - group_sums_array[lightest_grp]) / 2;

        // Find item in heaviest group closest to target_move_weight
        int best_item_to_move = -1;
        long long best_diff = LLONG_MAX;
        for (int item : group_items_indices[heaviest_grp]) {
            long long diff = std::abs(estimated_weights[item] - target_move_weight);
            if (diff < best_diff) {
                best_diff = diff;
                best_item_to_move = item;
            }
        }

        if (best_item_to_move == -1) break;

